-- =============================================================================

-- 1. byoneStartSession (000007 fix)
CREATE OR REPLACE FUNCTION "byoneStartSession"(p_console_id UUID, p_customer_id UUID, p_notes TEXT, p_booked_duration_minutes INTEGER DEFAULT 0) RETURNS TABLE (id UUID, console_id UUID, customer_id UUID, start_time TIMESTAMPTZ, end_time TIMESTAMPTZ, end_scheduled_at TIMESTAMPTZ, booked_duration_minutes INT, duration_minutes INT, total_price NUMERIC, status VARCHAR, notes TEXT, created_at TIMESTAMPTZ, updated_at TIMESTAMPTZ) LANGUAGE plpgsql AS $$ DECLARE v_session_id UUID; v_status VARCHAR; v_end_scheduled TIMESTAMPTZ; BEGIN SELECT c.status INTO v_status FROM consoles c WHERE c.id = p_console_id FOR UPDATE; IF NOT FOUND THEN RAISE EXCEPTION 'CONSOLE_NOT_FOUND'; END IF; IF v_status != 'available' THEN RAISE EXCEPTION 'CONSOLE_NOT_AVAILABLE: %', v_status; END IF; IF EXISTS (SELECT 1 FROM sessions s2 WHERE s2.console_id = p_console_id AND s2.status = 'active') THEN RAISE EXCEPTION 'SESSION_ALREADY_ACTIVE'; END IF; IF p_booked_duration_minutes > 0 THEN v_end_scheduled := NOW() + (p_booked_duration_minutes * INTERVAL '1 minute'); END IF; v_session_id := uuid_generate_v4(); INSERT INTO sessions (id,console_id,customer_id,start_time,booked_duration_minutes,end_scheduled_at,status,notes,created_at,updated_at) VALUES (v_session_id,p_console_id,p_customer_id,NOW(),p_booked_duration_minutes,v_end_scheduled,'active',p_notes,NOW(),NOW()); UPDATE consoles SET status='in_use',updated_at=NOW() WHERE consoles.id=p_console_id; RETURN QUERY SELECT sessions.id,sessions.console_id,sessions.customer_id,sessions.start_time,sessions.end_time,sessions.end_scheduled_at,sessions.booked_duration_minutes,sessions.duration_minutes,sessions.total_price,sessions.status,sessions.notes,sessions.created_at,sessions.updated_at FROM sessions WHERE sessions.id=v_session_id; END; $$;

-- 2. byoneEndSession (000013 duration cap fix)
CREATE OR REPLACE FUNCTION "byoneEndSession"(p_session_id UUID) RETURNS TABLE (id UUID, console_id UUID, customer_id UUID, start_time TIMESTAMPTZ, end_time TIMESTAMPTZ, duration_minutes INT, total_price NUMERIC, status VARCHAR, notes TEXT, created_at TIMESTAMPTZ, updated_at TIMESTAMPTZ) LANGUAGE plpgsql AS $$ DECLARE v_session sessions%ROWTYPE; v_price_per_hour NUMERIC; v_duration_min INT; v_total_price NUMERIC; v_now TIMESTAMPTZ:=NOW(); BEGIN SELECT * INTO v_session FROM sessions WHERE sessions.id=p_session_id FOR UPDATE; IF NOT FOUND THEN RAISE EXCEPTION 'SESSION_NOT_FOUND'; END IF; IF v_session.status!='active' THEN RAISE EXCEPTION 'SESSION_NOT_ACTIVE: %', v_session.status; END IF; SELECT price_per_hour INTO v_price_per_hour FROM consoles WHERE consoles.id=v_session.console_id; v_duration_min:=EXTRACT(EPOCH FROM (v_now-v_session.start_time))::INT/60; IF v_session.booked_duration_minutes>0 AND v_duration_min>v_session.booked_duration_minutes THEN v_duration_min:=v_session.booked_duration_minutes; END IF; v_total_price:=ROUND((v_duration_min::NUMERIC/60.0)*v_price_per_hour,2); IF v_duration_min<1 THEN v_duration_min:=1; END IF; IF v_total_price<0 THEN v_total_price:=0; END IF; UPDATE sessions SET end_time=v_now,duration_minutes=v_duration_min,total_price=v_total_price,status='completed',updated_at=v_now WHERE sessions.id=p_session_id; UPDATE consoles SET status='available',updated_at=v_now WHERE consoles.id=v_session.console_id; RETURN QUERY SELECT sessions.id,sessions.console_id,sessions.customer_id,sessions.start_time,sessions.end_time,sessions.duration_minutes,sessions.total_price,sessions.status,sessions.notes,sessions.created_at,sessions.updated_at FROM sessions WHERE sessions.id=p_session_id; END; $$;

-- 3. byoneCancelSession
CREATE OR REPLACE FUNCTION "byoneCancelSession"(p_session_id UUID) RETURNS VOID LANGUAGE plpgsql AS $$ DECLARE v_console_id UUID; v_status VARCHAR; BEGIN SELECT console_id,status INTO v_console_id,v_status FROM sessions WHERE id=p_session_id FOR UPDATE; IF NOT FOUND THEN RAISE EXCEPTION 'SESSION_NOT_FOUND'; END IF; IF v_status!='active' THEN RAISE EXCEPTION 'SESSION_NOT_ACTIVE: %', v_status; END IF; UPDATE sessions SET status='cancelled',updated_at=NOW() WHERE id=p_session_id; UPDATE consoles SET status='available',updated_at=NOW() WHERE id=v_console_id; END; $$;

-- 4. byoneRefundPayment
CREATE OR REPLACE FUNCTION "byoneRefundPayment"(p_payment_id UUID) RETURNS VOID LANGUAGE plpgsql AS $$ DECLARE v_status VARCHAR; BEGIN SELECT payment_status INTO v_status FROM payments WHERE id=p_payment_id FOR UPDATE; IF NOT FOUND THEN RAISE EXCEPTION 'PAYMENT_NOT_FOUND'; END IF; IF v_status!='paid' THEN RAISE EXCEPTION 'PAYMENT_NOT_PAID: %', v_status; END IF; UPDATE payments SET payment_status='refunded',updated_at=NOW() WHERE id=p_payment_id; END; $$;

-- 5. byoneValidateKasirShift
CREATE OR REPLACE FUNCTION "byoneValidateKasirShift"(p_user_id UUID) RETURNS BOOLEAN LANGUAGE plpgsql AS $$ DECLARE v_role VARCHAR; v_hour SMALLINT; v_shift RECORD; BEGIN SELECT role INTO v_role FROM users WHERE id=p_user_id AND is_active=TRUE; IF NOT FOUND THEN RETURN FALSE; END IF; IF v_role IN ('superadmin','admin') THEN RETURN TRUE; END IF; v_hour:=EXTRACT(HOUR FROM NOW() AT TIME ZONE 'Asia/Jakarta')::SMALLINT; FOR v_shift IN SELECT * FROM shifts WHERE user_id=p_user_id AND status='active' LOOP IF v_shift.is_24_hour THEN RETURN TRUE; END IF; IF v_shift.start_hour>v_shift.end_hour THEN IF v_hour>=v_shift.start_hour OR v_hour<v_shift.end_hour THEN RETURN TRUE; END IF; ELSE IF v_hour>=v_shift.start_hour AND v_hour<v_shift.end_hour THEN RETURN TRUE; END IF; END IF; END LOOP; RETURN FALSE; END; $$;

-- 6. byoneApplyVoucher (free_days support)
CREATE OR REPLACE FUNCTION "byoneApplyVoucher"(p_code VARCHAR, p_total_price NUMERIC, p_daily_price NUMERIC DEFAULT NULL, p_total_days INT DEFAULT NULL) RETURNS TABLE(voucher_id UUID, discount_amount NUMERIC, free_days_used INT) LANGUAGE plpgsql AS $$ DECLARE v_voucher vouchers%ROWTYPE; v_discount NUMERIC(10,2):=0; v_free_days INT:=0; BEGIN SELECT * INTO v_voucher FROM vouchers WHERE code=UPPER(p_code); IF NOT FOUND THEN RAISE EXCEPTION 'VOUCHER_NOT_FOUND'; END IF; IF NOT v_voucher.is_active THEN RAISE EXCEPTION 'VOUCHER_INACTIVE'; END IF; IF v_voucher.expires_at IS NOT NULL AND v_voucher.expires_at<NOW() THEN RAISE EXCEPTION 'VOUCHER_EXPIRED'; END IF; IF v_voucher.max_usage>0 AND v_voucher.usage_count>=v_voucher.max_usage THEN RAISE EXCEPTION 'VOUCHER_LIMIT_REACHED'; END IF; IF v_voucher.discount_type='free_days' THEN IF p_daily_price IS NULL OR p_total_days IS NULL THEN RAISE EXCEPTION 'VOUCHER_INVALID_TARGET'; END IF; v_free_days:=LEAST(v_voucher.discount_value::INT,p_total_days); v_discount:=v_free_days*p_daily_price; ELSIF v_voucher.discount_type='percentage' THEN IF p_total_price<v_voucher.min_purchase THEN RAISE EXCEPTION 'VOUCHER_MIN_PURCHASE: Rp %.0f',v_voucher.min_purchase; END IF; v_discount:=ROUND((p_total_price*v_voucher.discount_value/100)::NUMERIC,2); IF v_voucher.max_discount>0 AND v_discount>v_voucher.max_discount THEN v_discount:=v_voucher.max_discount; END IF; ELSE IF p_total_price<v_voucher.min_purchase THEN RAISE EXCEPTION 'VOUCHER_MIN_PURCHASE: Rp %.0f',v_voucher.min_purchase; END IF; v_discount:=v_voucher.discount_value; IF v_discount>p_total_price THEN v_discount:=p_total_price; END IF; END IF; RETURN QUERY SELECT v_voucher.id,v_discount,v_free_days; END; $$;

-- 7. byoneEvaluateDiscountRules
CREATE OR REPLACE FUNCTION "byoneEvaluateDiscountRules"(p_total_price NUMERIC, p_session_start_time TIMESTAMPTZ, p_is_member BOOLEAN DEFAULT FALSE) RETURNS NUMERIC LANGUAGE plpgsql AS $$ DECLARE v_dow INT; v_hour INT; v_total_disc NUMERIC(10,2):=0; v_disc NUMERIC(10,2); r RECORD; BEGIN v_dow:=EXTRACT(DOW FROM p_session_start_time AT TIME ZONE 'Asia/Jakarta')::INT; v_hour:=EXTRACT(HOUR FROM p_session_start_time AT TIME ZONE 'Asia/Jakarta')::INT; FOR r IN SELECT * FROM discount_rules WHERE is_active=TRUE ORDER BY priority DESC, created_at ASC LOOP CASE r.rule_type WHEN 'always' THEN NULL; WHEN 'happy_hour' THEN IF r.start_hour IS NULL OR r.end_hour IS NULL THEN CONTINUE; END IF; IF r.start_hour>r.end_hour THEN IF NOT (v_hour>=r.start_hour OR v_hour<r.end_hour) THEN CONTINUE; END IF; ELSE IF NOT (v_hour>=r.start_hour AND v_hour<r.end_hour) THEN CONTINUE; END IF; END IF; WHEN 'member' THEN IF NOT p_is_member THEN CONTINUE; END IF; WHEN 'day_of_week' THEN IF r.days_of_week IS NULL OR TRIM(r.days_of_week)='' THEN CONTINUE; END IF; IF NOT (v_dow=ANY(string_to_array(r.days_of_week,',')::INT[])) THEN CONTINUE; END IF; ELSE CONTINUE; END CASE; IF p_total_price<r.min_purchase THEN CONTINUE; END IF; IF r.discount_type='percentage' THEN v_disc:=ROUND((p_total_price*r.discount_value/100)::NUMERIC,2); IF r.max_discount>0 AND v_disc>r.max_discount THEN v_disc:=r.max_discount; END IF; ELSE v_disc:=r.discount_value; IF v_disc>p_total_price THEN v_disc:=p_total_price; END IF; END IF; v_total_disc:=v_total_disc+v_disc; END LOOP; IF v_total_disc>p_total_price THEN v_total_disc:=p_total_price; END IF; RETURN v_total_disc; END; $$;

-- 8. byoneCalculatePrice (tiered pricing)
CREATE OR REPLACE FUNCTION "byoneCalculatePrice"(p_console_id UUID, p_duration_minutes INTEGER) RETURNS TABLE(base_amount NUMERIC, price_per_hour NUMERIC, breakdown JSONB, tier_count INT) LANGUAGE plpgsql AS $$ DECLARE v_console consoles%ROWTYPE; v_tiers JSONB; v_tier JSONB; v_total NUMERIC(10,2):=0; v_breakdown JSONB:='[]'::JSONB; v_tier_start INT; v_tier_end INT; v_tier_price NUMERIC(10,2); v_minutes_in_tier INT; v_subtotal NUMERIC(10,2); v_idx INT:=0; v_tier_used INT:=0; v_remaining INT:=p_duration_minutes; BEGIN IF p_duration_minutes<=0 THEN RAISE EXCEPTION 'INVALID_DURATION'; END IF; SELECT * INTO v_console FROM consoles WHERE consoles.id=p_console_id; IF NOT FOUND THEN RAISE EXCEPTION 'CONSOLE_NOT_FOUND'; END IF; v_tiers:=v_console.pricing_tiers; IF v_tiers IS NULL OR jsonb_array_length(v_tiers)=0 THEN v_total:=ROUND((p_duration_minutes::NUMERIC/60.0)*v_console.price_per_hour,2); RETURN QUERY SELECT v_total,v_console.price_per_hour,jsonb_build_array(jsonb_build_object('startMinute',0,'endMinute',p_duration_minutes,'minutes',p_duration_minutes,'pricePerHour',v_console.price_per_hour,'subtotal',v_total)),1; RETURN; END IF; v_remaining:=p_duration_minutes; FOR v_idx IN 0..jsonb_array_length(v_tiers)-1 LOOP v_tier:=v_tiers->v_idx; v_tier_start:=(v_tier->>'startMinute')::INT; v_tier_end:=(v_tier->>'endMinute')::INT; v_tier_price:=(v_tier->>'price')::NUMERIC(10,2); IF v_remaining<=0 THEN EXIT; END IF; IF v_tier_end IS NULL THEN v_minutes_in_tier:=v_remaining; ELSE v_minutes_in_tier:=LEAST(v_remaining,v_tier_end-v_tier_start); IF v_minutes_in_tier<=0 THEN CONTINUE; END IF; END IF; v_subtotal:=ROUND((v_minutes_in_tier::NUMERIC/60.0)*v_tier_price,2); v_total:=v_total+v_subtotal; v_breakdown:=v_breakdown||jsonb_build_object('startMinute',v_tier_start,'endMinute',v_tier_end,'minutes',v_minutes_in_tier,'pricePerHour',v_tier_price,'subtotal',v_subtotal); v_tier_used:=v_tier_used+1; v_remaining:=v_remaining-v_minutes_in_tier; END LOOP; IF v_remaining>0 THEN v_subtotal:=ROUND((v_remaining::NUMERIC/60.0)*v_console.price_per_hour,2); v_total:=v_total+v_subtotal; v_breakdown:=v_breakdown||jsonb_build_object('startMinute',p_duration_minutes-v_remaining,'endMinute',p_duration_minutes,'minutes',v_remaining,'pricePerHour',v_console.price_per_hour,'subtotal',v_subtotal,'fallback',true); v_tier_used:=v_tier_used+1; END IF; RETURN QUERY SELECT v_total,v_console.price_per_hour,v_breakdown,v_tier_used; END; $$;

-- 9. byonePreviewPrice (min 1 menit)
CREATE OR REPLACE FUNCTION "byonePreviewPrice"(p_console_id UUID, p_duration_minutes INTEGER, p_voucher_code VARCHAR DEFAULT NULL, p_customer_id UUID DEFAULT NULL) RETURNS TABLE(price_per_hour NUMERIC, duration_minutes INT, base_amount NUMERIC, auto_discount NUMERIC, voucher_discount NUMERIC, total_discount NUMERIC, final_amount NUMERIC, voucher_applied BOOLEAN, voucher_name VARCHAR, price_breakdown JSONB, tier_count INT, message VARCHAR) LANGUAGE plpgsql AS $$ DECLARE v_price_per_hour NUMERIC(10,2); v_status VARCHAR; v_amount NUMERIC(10,2); v_breakdown JSONB; v_tier_count INT; v_auto_discount NUMERIC(10,2):=0; v_voucher_discount NUMERIC(10,2):=0; v_voucher_id UUID; v_voucher_name VARCHAR; v_is_member BOOLEAN:=FALSE; v_total_disc NUMERIC(10,2); v_final NUMERIC(10,2); v_voucher_ok BOOLEAN:=FALSE; v_msg VARCHAR:=''; BEGIN IF p_duration_minutes<=0 THEN RAISE EXCEPTION 'INVALID_DURATION: minimal 1 menit'; END IF; SELECT c.price_per_hour,c.status INTO v_price_per_hour,v_status FROM consoles c WHERE c.id=p_console_id; IF NOT FOUND THEN RAISE EXCEPTION 'CONSOLE_NOT_FOUND'; END IF; IF v_status!='available' THEN v_msg:='Konsol tidak tersedia ('||v_status||')'; END IF; SELECT pc.base_amount,pc.breakdown,pc.tier_count INTO v_amount,v_breakdown,v_tier_count FROM "byoneCalculatePrice"(p_console_id,p_duration_minutes) pc; IF p_customer_id IS NOT NULL THEN SELECT COALESCE(is_member,FALSE) INTO v_is_member FROM customers WHERE id=p_customer_id; END IF; v_auto_discount:="byoneEvaluateDiscountRules"(v_amount,NOW(),v_is_member); IF p_voucher_code IS NOT NULL AND TRIM(p_voucher_code)!='' THEN BEGIN SELECT va.voucher_id,va.discount_amount INTO v_voucher_id,v_voucher_discount FROM "byoneApplyVoucher"(p_voucher_code,v_amount) va; v_voucher_ok:=TRUE; SELECT name INTO v_voucher_name FROM vouchers WHERE id=v_voucher_id; EXCEPTION WHEN OTHERS THEN v_voucher_discount:=0; v_voucher_ok:=FALSE; v_msg:=v_msg||' Voucher tidak valid.'; END; END IF; v_total_disc:=v_auto_discount+v_voucher_discount; IF v_total_disc>v_amount THEN v_total_disc:=v_amount; END IF; v_final:=GREATEST(v_amount-v_total_disc,0); IF v_msg='' AND v_status='available' THEN v_msg:='Tersedia. Rp '||v_final::TEXT||' / '||p_duration_minutes::TEXT||' menit'; END IF; RETURN QUERY SELECT v_price_per_hour,p_duration_minutes,v_amount,v_auto_discount,v_voucher_discount,v_total_disc,v_final,v_voucher_ok,v_voucher_name,v_breakdown,v_tier_count,v_msg; END; $$;

-- 10. byoneStartSessionWithPayment (min 1 menit, tiered)
CREATE OR REPLACE FUNCTION "byoneStartSessionWithPayment"(p_console_id UUID, p_customer_id UUID, p_notes TEXT, p_booked_duration_minutes INTEGER, p_cash_received NUMERIC, p_voucher_code VARCHAR DEFAULT NULL) RETURNS TABLE(session_id UUID, session_status VARCHAR, session_start_time TIMESTAMPTZ, session_booked_minutes INT, session_end_scheduled TIMESTAMPTZ, payment_id UUID, base_amount NUMERIC, discount_amount NUMERIC, auto_discount_amount NUMERIC, total_payment NUMERIC, cash_received NUMERIC, change_amount NUMERIC, voucher_id UUID, paid_at TIMESTAMPTZ) LANGUAGE plpgsql AS $$ DECLARE v_session_id UUID; v_payment_id UUID; v_console_status VARCHAR; v_price_per_hour NUMERIC(10,2); v_end_scheduled TIMESTAMPTZ; v_amount NUMERIC(10,2); v_voucher_discount NUMERIC(10,2):=0; v_auto_discount NUMERIC(10,2):=0; v_total_discount NUMERIC(10,2); v_final_amount NUMERIC(10,2); v_change NUMERIC(10,2); v_voucher_id UUID:=NULL; v_is_member BOOLEAN:=FALSE; v_now TIMESTAMPTZ:=NOW(); BEGIN IF p_booked_duration_minutes<=0 THEN RAISE EXCEPTION 'INVALID_DURATION: minimal 1 menit'; END IF; SELECT c.status,c.price_per_hour INTO v_console_status,v_price_per_hour FROM consoles c WHERE c.id=p_console_id FOR UPDATE; IF NOT FOUND THEN RAISE EXCEPTION 'CONSOLE_NOT_FOUND'; END IF; IF v_console_status!='available' THEN RAISE EXCEPTION 'CONSOLE_NOT_AVAILABLE: %',v_console_status; END IF; IF EXISTS(SELECT 1 FROM sessions s2 WHERE s2.console_id=p_console_id AND s2.status='active') THEN RAISE EXCEPTION 'SESSION_ALREADY_ACTIVE'; END IF; SELECT pc.base_amount INTO v_amount FROM "byoneCalculatePrice"(p_console_id,p_booked_duration_minutes) pc; v_end_scheduled:=v_now+(p_booked_duration_minutes*INTERVAL'1 minute'); IF p_customer_id IS NOT NULL THEN SELECT COALESCE(is_member,FALSE) INTO v_is_member FROM customers WHERE id=p_customer_id; END IF; v_auto_discount:="byoneEvaluateDiscountRules"(v_amount,v_now,v_is_member); IF p_voucher_code IS NOT NULL AND TRIM(p_voucher_code)!='' THEN SELECT va.voucher_id,va.discount_amount INTO v_voucher_id,v_voucher_discount FROM "byoneApplyVoucher"(p_voucher_code,v_amount) va; UPDATE vouchers SET usage_count=usage_count+1,updated_at=v_now WHERE id=v_voucher_id; END IF; v_total_discount:=v_auto_discount+v_voucher_discount; IF v_total_discount>v_amount THEN v_total_discount:=v_amount; IF v_auto_discount>v_amount THEN v_auto_discount:=v_amount; v_voucher_discount:=0; ELSE v_voucher_discount:=v_amount-v_auto_discount; END IF; END IF; v_final_amount:=GREATEST(v_amount-v_total_discount,0); IF p_cash_received<v_final_amount THEN RAISE EXCEPTION 'INSUFFICIENT_CASH: butuh Rp %.0f',v_final_amount; END IF; v_change:=p_cash_received-v_final_amount; v_session_id:=uuid_generate_v4(); INSERT INTO sessions(id,console_id,customer_id,start_time,booked_duration_minutes,end_scheduled_at,total_price,status,notes,created_at,updated_at) VALUES(v_session_id,p_console_id,p_customer_id,v_now,p_booked_duration_minutes,v_end_scheduled,v_amount,'active',p_notes,v_now,v_now); UPDATE consoles SET status='in_use',updated_at=v_now WHERE consoles.id=p_console_id; v_payment_id:=uuid_generate_v4(); INSERT INTO payments(id,session_id,amount,discount_amount,auto_discount_amount,total_payment,payment_method,payment_status,cash_received,change_amount,voucher_id,notes,paid_at,created_at,updated_at) VALUES(v_payment_id,v_session_id,v_amount,v_voucher_discount,v_auto_discount,v_final_amount,'cash','paid',p_cash_received,v_change,v_voucher_id,p_notes,v_now,v_now,v_now); RETURN QUERY SELECT v_session_id,'active'::VARCHAR,v_now,p_booked_duration_minutes,v_end_scheduled,v_payment_id,v_amount,v_voucher_discount,v_auto_discount,v_final_amount,p_cash_received,v_change,v_voucher_id,v_now; END; $$;

-- 11. byoneCreatePayment (FIXED: byoneEvaluateDiscountRules)
CREATE OR REPLACE FUNCTION "byoneCreatePayment"(p_session_id UUID, p_cash_received NUMERIC, p_notes TEXT DEFAULT NULL, p_voucher_code VARCHAR DEFAULT NULL) RETURNS TABLE(payment_id UUID, amount NUMERIC, discount_amount NUMERIC, auto_discount_amount NUMERIC, total_payment NUMERIC, cash_received NUMERIC, change_amount NUMERIC, voucher_id UUID, paid_at TIMESTAMPTZ) LANGUAGE plpgsql AS $$ DECLARE v_session sessions%ROWTYPE; v_payment_id UUID; v_amount NUMERIC(10,2); v_voucher_discount NUMERIC(10,2):=0; v_auto_discount NUMERIC(10,2):=0; v_total_discount NUMERIC(10,2); v_final_amount NUMERIC(10,2); v_change NUMERIC(10,2); v_voucher_id UUID:=NULL; v_is_member BOOLEAN:=FALSE; v_now TIMESTAMPTZ:=NOW(); BEGIN SELECT * INTO v_session FROM sessions WHERE id=p_session_id FOR UPDATE; IF NOT FOUND THEN RAISE EXCEPTION 'SESSION_NOT_FOUND'; END IF; IF v_session.status!='completed' THEN RAISE EXCEPTION 'SESSION_NOT_COMPLETED'; END IF; IF EXISTS(SELECT 1 FROM payments WHERE session_id=p_session_id AND payment_status!='refunded') THEN RAISE EXCEPTION 'PAYMENT_EXISTS'; END IF; v_amount:=v_session.total_price; IF v_session.customer_id IS NOT NULL THEN SELECT COALESCE(is_member,FALSE) INTO v_is_member FROM customers WHERE id=v_session.customer_id; END IF; v_auto_discount:=COALESCE("byoneEvaluateDiscountRules"(v_amount,v_session.start_time,v_is_member),0); IF p_voucher_code IS NOT NULL AND TRIM(p_voucher_code)!='' THEN BEGIN SELECT va.voucher_id,va.discount_amount INTO v_voucher_id,v_voucher_discount FROM "byoneApplyVoucher"(p_voucher_code,v_amount) va; UPDATE vouchers SET usage_count=usage_count+1,updated_at=v_now WHERE id=v_voucher_id; EXCEPTION WHEN OTHERS THEN v_voucher_discount:=0; END; END IF; v_total_discount:=v_auto_discount+v_voucher_discount; IF v_total_discount>v_amount THEN v_total_discount:=v_amount; IF v_auto_discount>v_amount THEN v_auto_discount:=v_amount; v_voucher_discount:=0; ELSE v_voucher_discount:=v_amount-v_auto_discount; END IF; END IF; v_final_amount:=GREATEST(v_amount-v_total_discount,0); IF p_cash_received<v_final_amount THEN RAISE EXCEPTION 'INSUFFICIENT_CASH: butuh Rp %.0f',v_final_amount; END IF; v_change:=p_cash_received-v_final_amount; v_payment_id:=uuid_generate_v4(); INSERT INTO payments(session_id,amount,discount_amount,auto_discount_amount,total_payment,payment_method,payment_status,cash_received,change_amount,voucher_id,notes,paid_at,created_at,updated_at) VALUES(p_session_id,v_amount,v_voucher_discount,v_auto_discount,v_final_amount,'cash','paid',p_cash_received,v_change,v_voucher_id,p_notes,v_now,v_now,v_now); RETURN QUERY SELECT v_payment_id,v_amount,v_voucher_discount,v_auto_discount,v_final_amount,p_cash_received,v_change,v_voucher_id,v_now; END; $$;

-- 12. byoneExtendSession (payNow option)
CREATE OR REPLACE FUNCTION "byoneExtendSession"(p_session_id UUID, p_additional_minutes INTEGER, p_cash_received NUMERIC, p_pay_now BOOLEAN DEFAULT TRUE, p_voucher_code VARCHAR DEFAULT NULL, p_notes TEXT DEFAULT NULL) RETURNS TABLE(session_id UUID, session_booked_minutes INT, session_end_scheduled TIMESTAMPTZ, payment_id UUID, payment_amount NUMERIC, payment_discount NUMERIC, payment_total NUMERIC, payment_cash_received NUMERIC, payment_change NUMERIC, payment_voucher_id UUID, payment_status VARCHAR, payment_paid_at TIMESTAMPTZ) LANGUAGE plpgsql AS $$ DECLARE v_session sessions%ROWTYPE; v_payment_id UUID; v_amount NUMERIC(10,2); v_voucher_discount NUMERIC(10,2):=0; v_voucher_id UUID:=NULL; v_final_amount NUMERIC(10,2); v_change NUMERIC(10,2); v_new_booked INT; v_new_end TIMESTAMPTZ; v_now TIMESTAMPTZ:=NOW(); v_status VARCHAR; v_paid_at TIMESTAMPTZ; BEGIN SELECT * INTO v_session FROM sessions WHERE sessions.id=p_session_id FOR UPDATE; IF NOT FOUND THEN RAISE EXCEPTION 'SESSION_NOT_FOUND'; END IF; IF v_session.status!='active' THEN RAISE EXCEPTION 'SESSION_NOT_ACTIVE'; END IF; IF p_additional_minutes<=0 THEN RAISE EXCEPTION 'INVALID_DURATION: minimal 1 menit'; END IF; DECLARE v_new_total NUMERIC(10,2); v_old_total NUMERIC(10,2):=v_session.total_price; v_total_minutes INT:=v_session.booked_duration_minutes+p_additional_minutes; BEGIN SELECT pc.base_amount INTO v_new_total FROM "byoneCalculatePrice"(v_session.console_id,v_total_minutes) pc; v_amount:=v_new_total-v_old_total; IF v_amount<0 THEN v_amount:=0; END IF; END; IF p_voucher_code IS NOT NULL AND TRIM(p_voucher_code)!='' THEN BEGIN SELECT va.voucher_id,va.discount_amount INTO v_voucher_id,v_voucher_discount FROM "byoneApplyVoucher"(p_voucher_code,v_amount) va; EXCEPTION WHEN OTHERS THEN v_voucher_discount:=0; v_voucher_id:=NULL; END; IF v_voucher_id IS NOT NULL THEN UPDATE vouchers SET usage_count=usage_count+1,updated_at=v_now WHERE id=v_voucher_id; END IF; END IF; IF v_voucher_discount>v_amount THEN v_voucher_discount:=v_amount; END IF; v_final_amount:=v_amount-v_voucher_discount; IF v_final_amount<0 THEN v_final_amount:=0; END IF; v_change:=GREATEST(p_cash_received-v_final_amount,0); v_new_booked:=v_session.booked_duration_minutes+p_additional_minutes; v_new_end:=v_now+(v_new_booked*INTERVAL'1 minute'); UPDATE sessions SET booked_duration_minutes=v_new_booked,end_scheduled_at=v_new_end,total_price=v_session.total_price+v_amount,updated_at=v_now WHERE sessions.id=p_session_id; IF p_pay_now THEN v_status:='paid'; v_paid_at:=v_now; ELSE v_status:='pending'; v_paid_at:=NULL; END IF; v_payment_id:=uuid_generate_v4(); INSERT INTO payments(id,session_id,amount,discount_amount,auto_discount_amount,total_payment,payment_method,payment_status,cash_received,change_amount,voucher_id,notes,paid_at,created_at,updated_at) VALUES(v_payment_id,p_session_id,v_amount,v_voucher_discount,0,v_final_amount,'cash',v_status,p_cash_received,v_change,v_voucher_id,p_notes,v_paid_at,v_now,v_now); RETURN QUERY SELECT p_session_id,v_new_booked,v_new_end,v_payment_id,v_amount,v_voucher_discount,v_final_amount,p_cash_received,v_change,v_voucher_id,v_status,v_paid_at; END; $$;

-- 13. byoneConfirmExtendPayment (000030 fix ambiguous)
CREATE OR REPLACE FUNCTION "byoneConfirmExtendPayment"(p_payment_id UUID) RETURNS TABLE(payment_id UUID, payment_status VARCHAR, paid_at TIMESTAMPTZ) LANGUAGE plpgsql AS $$ DECLARE v_payment payments%ROWTYPE; v_now TIMESTAMPTZ:=NOW(); v_pending BIGINT; v_console_id UUID; BEGIN SELECT * INTO v_payment FROM payments WHERE payments.id=p_payment_id FOR UPDATE; IF NOT FOUND THEN RAISE EXCEPTION 'PAYMENT_NOT_FOUND'; END IF; IF v_payment.payment_status!='pending' THEN RAISE EXCEPTION 'PAYMENT_NOT_PENDING'; END IF; UPDATE payments SET payment_status='paid',paid_at=v_now,updated_at=v_now WHERE payments.id=p_payment_id; SELECT COUNT(*) INTO v_pending FROM payments WHERE payments.session_id=v_payment.session_id AND payments.payment_status='pending'; IF v_pending=0 THEN SELECT s.console_id INTO v_console_id FROM sessions s WHERE s.id=v_payment.session_id; IF v_console_id IS NOT NULL THEN UPDATE tv_notifications SET is_active=false,updated_at=v_now WHERE title='Pembayaran Tertunda' AND is_active=true AND (target_all=true OR target_console_ids::jsonb@>to_jsonb(v_console_id::TEXT)); END IF; END IF; RETURN QUERY SELECT p_payment_id,'paid'::VARCHAR,v_now; END; $$;

-- 14. generate_food_order_number
CREATE OR REPLACE FUNCTION "generate_food_order_number"() RETURNS VARCHAR LANGUAGE plpgsql AS $$ DECLARE v_date VARCHAR(8); v_seq INT; v_number VARCHAR(20); BEGIN v_date:=TO_CHAR(NOW() AT TIME ZONE 'Asia/Jakarta','YYYYMMDD'); SELECT COALESCE(MAX(CAST(SPLIT_PART(order_number,'-',3) AS INT)),0)+1 INTO v_seq FROM food_orders WHERE order_number LIKE 'F-'||v_date||'-%'; v_number:='F-'||v_date||'-'||LPAD(v_seq::TEXT,3,'0'); RETURN v_number; END; $$;

-- 15. byoneCreateFoodOrder
CREATE OR REPLACE FUNCTION "byoneCreateFoodOrder"(p_session_id UUID, p_customer_id UUID, p_notes TEXT, p_items JSONB) RETURNS TABLE(order_id UUID, order_number VARCHAR, total_amount NUMERIC) LANGUAGE plpgsql AS $$ DECLARE v_order_id UUID; v_order_number VARCHAR(20); v_total NUMERIC(10,2):=0; v_item JSONB; v_menu_item_id UUID; v_quantity INT; v_item_notes TEXT; v_price NUMERIC(10,2); v_subtotal NUMERIC(10,2); v_available BOOLEAN; BEGIN IF p_items IS NULL OR jsonb_array_length(p_items)=0 THEN RAISE EXCEPTION 'ORDER_EMPTY'; END IF; v_order_number:=generate_food_order_number(); v_order_id:=uuid_generate_v4(); INSERT INTO food_orders(id,order_number,session_id,customer_id,status,total_amount,notes,created_at,updated_at) VALUES(v_order_id,v_order_number,p_session_id,p_customer_id,'pending',0,p_notes,NOW(),NOW()); FOR v_item IN SELECT * FROM jsonb_array_elements(p_items) LOOP v_menu_item_id:=(v_item->>'menu_item_id')::UUID; v_quantity:=(v_item->>'quantity')::INT; v_item_notes:=v_item->>'notes'; IF v_quantity<=0 THEN RAISE EXCEPTION 'INVALID_QUANTITY'; END IF; SELECT price,is_available INTO v_price,v_available FROM menu_items WHERE id=v_menu_item_id; IF NOT FOUND THEN RAISE EXCEPTION 'MENU_NOT_FOUND: %',v_menu_item_id; END IF; IF NOT v_available THEN RAISE EXCEPTION 'MENU_UNAVAILABLE'; END IF; v_subtotal:=v_price*v_quantity; v_total:=v_total+v_subtotal; INSERT INTO food_order_items(id,order_id,menu_item_id,quantity,unit_price,subtotal,notes,created_at) VALUES(uuid_generate_v4(),v_order_id,v_menu_item_id,v_quantity,v_price,v_subtotal,v_item_notes,NOW()); END LOOP; UPDATE food_orders SET total_amount=v_total,updated_at=NOW() WHERE id=v_order_id; RETURN QUERY SELECT v_order_id,v_order_number,v_total; END; $$;

-- 16. byoneUpdateFoodOrderStatus
CREATE OR REPLACE FUNCTION "byoneUpdateFoodOrderStatus"(p_order_id UUID, p_status VARCHAR) RETURNS VOID LANGUAGE plpgsql AS $$ DECLARE v_current_status VARCHAR; BEGIN SELECT status INTO v_current_status FROM food_orders WHERE id=p_order_id FOR UPDATE; IF NOT FOUND THEN RAISE EXCEPTION 'ORDER_NOT_FOUND'; END IF; IF v_current_status='cancelled' THEN RAISE EXCEPTION 'ORDER_CANCELLED'; END IF; IF v_current_status='served' AND p_status!='cancelled' THEN RAISE EXCEPTION 'ORDER_SERVED'; END IF; UPDATE food_orders SET status=p_status,updated_at=NOW() WHERE id=p_order_id; END; $$;

-- 17. byoneCreateDailyRental (000022 fix: voucher_id for free_days)
CREATE OR REPLACE FUNCTION "byoneCreateDailyRental"(p_console_id UUID, p_customer_id UUID, p_start_date DATE, p_end_date DATE, p_daily_price NUMERIC, p_voucher_code VARCHAR DEFAULT NULL, p_notes TEXT DEFAULT NULL) RETURNS TABLE(rental_id UUID, total_days INT, total_amount NUMERIC, discount_amount NUMERIC, free_days_used INT, final_amount NUMERIC, status VARCHAR) LANGUAGE plpgsql AS $$ DECLARE v_rental_id UUID; v_console_stat VARCHAR; v_total_days INT; v_total_amount NUMERIC(10,2); v_voucher_discount NUMERIC(10,2):=0; v_free_days INT:=0; v_final_amount NUMERIC(10,2); v_actual_end_date DATE; v_voucher_type VARCHAR(20); v_voucher_id UUID:=NULL; v_now TIMESTAMPTZ:=NOW(); BEGIN SELECT c.status INTO v_console_stat FROM consoles c WHERE c.id=p_console_id FOR UPDATE; IF NOT FOUND THEN RAISE EXCEPTION 'CONSOLE_NOT_FOUND'; END IF; IF v_console_stat!='available' THEN RAISE EXCEPTION 'CONSOLE_NOT_AVAILABLE: %',v_console_stat; END IF; IF p_end_date<=p_start_date THEN RAISE EXCEPTION 'INVALID_DATE'; END IF; v_total_days:=p_end_date-p_start_date; IF v_total_days<1 THEN v_total_days:=1; END IF; v_total_amount:=v_total_days*p_daily_price; IF p_voucher_code IS NOT NULL AND TRIM(p_voucher_code)!='' THEN SELECT discount_type INTO v_voucher_type FROM vouchers WHERE code=UPPER(p_voucher_code); IF v_voucher_type='free_days' THEN BEGIN SELECT va.voucher_id,va.free_days_used INTO v_voucher_id,v_free_days FROM "byoneApplyVoucher"(p_voucher_code,v_total_amount,p_daily_price,v_total_days) va; UPDATE vouchers SET usage_count=usage_count+1,updated_at=v_now WHERE code=UPPER(p_voucher_code); EXCEPTION WHEN OTHERS THEN v_free_days:=0; END; v_voucher_discount:=0; ELSE BEGIN SELECT va.voucher_id,va.discount_amount INTO v_voucher_id,v_voucher_discount FROM "byoneApplyVoucher"(p_voucher_code,v_total_amount) va; UPDATE vouchers SET usage_count=usage_count+1,updated_at=v_now WHERE code=UPPER(p_voucher_code); EXCEPTION WHEN OTHERS THEN v_voucher_discount:=0; END; v_free_days:=0; END IF; END IF; IF v_voucher_discount>v_total_amount THEN v_voucher_discount:=v_total_amount; END IF; v_final_amount:=v_total_amount-v_voucher_discount; v_rental_id:=uuid_generate_v4(); IF v_free_days>0 THEN v_total_days:=v_total_days+v_free_days; v_actual_end_date:=p_start_date+v_total_days; ELSE v_actual_end_date:=p_end_date; END IF; INSERT INTO daily_rentals(id,console_id,customer_id,start_date,end_date,daily_price,total_days,free_days_used,total_amount,discount_amount,final_amount,voucher_id,status,notes,created_at,updated_at) VALUES(v_rental_id,p_console_id,p_customer_id,p_start_date,v_actual_end_date,p_daily_price,v_total_days,v_free_days,v_total_amount,v_voucher_discount,v_final_amount,v_voucher_id,'active',p_notes,v_now,v_now); UPDATE consoles SET status='rented_out',updated_at=v_now WHERE consoles.id=p_console_id; RETURN QUERY SELECT v_rental_id,v_total_days,v_total_amount,v_voucher_discount,v_free_days,v_final_amount,'active'::VARCHAR; END; $$;

-- 18. byoneReturnDailyRental
CREATE OR REPLACE FUNCTION "byoneReturnDailyRental"(p_rental_id UUID) RETURNS TABLE(rental_id UUID, status VARCHAR, returned_at TIMESTAMPTZ) LANGUAGE plpgsql AS $$ DECLARE v_rental daily_rentals%ROWTYPE; v_now TIMESTAMPTZ:=NOW(); BEGIN SELECT * INTO v_rental FROM daily_rentals WHERE daily_rentals.id=p_rental_id FOR UPDATE; IF NOT FOUND THEN RAISE EXCEPTION 'RENTAL_NOT_FOUND'; END IF; IF v_rental.status!='active' AND v_rental.status!='overdue' THEN RAISE EXCEPTION 'RENTAL_NOT_ACTIVE'; END IF; UPDATE daily_rentals SET status='returned',returned_at=v_now,updated_at=v_now WHERE daily_rentals.id=p_rental_id; UPDATE consoles SET status='available',updated_at=v_now WHERE consoles.id=v_rental.console_id; RETURN QUERY SELECT p_rental_id,'returned'::VARCHAR,v_now; END; $$;

-- 19. byoneCreateBooking (customer_id optional)
CREATE OR REPLACE FUNCTION "byoneCreateBooking"(p_console_id UUID, p_customer_id UUID, p_booking_date DATE, p_start_hour INT, p_start_minute INT, p_duration_minutes INT, p_notes TEXT DEFAULT NULL) RETURNS TABLE(booking_id UUID, status VARCHAR) LANGUAGE plpgsql AS $$ DECLARE v_id UUID; v_start TIMESTAMPTZ; v_end TIMESTAMPTZ; v_conflict INT; v_console_exists BOOLEAN; BEGIN IF p_duration_minutes<30 THEN RAISE EXCEPTION 'INVALID_DURATION: min 30 menit'; END IF; SELECT EXISTS(SELECT 1 FROM consoles WHERE id=p_console_id) INTO v_console_exists; IF NOT v_console_exists THEN RAISE EXCEPTION 'CONSOLE_NOT_FOUND'; END IF; v_start:=p_booking_date+make_time(p_start_hour,p_start_minute,0); v_end:=v_start+(p_duration_minutes*INTERVAL'1 minute'); SELECT COUNT(*) INTO v_conflict FROM (SELECT s.console_id FROM sessions s WHERE s.console_id=p_console_id AND s.status='active' AND s.start_time<v_end AND COALESCE(s.end_scheduled_at,s.start_time+(s.booked_duration_minutes*INTERVAL'1 minute'))>v_start UNION ALL SELECT b.console_id FROM bookings b WHERE b.console_id=p_console_id AND b.status IN('pending','confirmed') AND b.booking_date=p_booking_date AND make_time(b.start_hour,b.start_minute,0)<v_end::TIME AND make_time(b.start_hour,b.start_minute,0)+(b.duration_minutes*INTERVAL'1 minute')>v_start::TIME) conflicts; IF v_conflict>0 THEN RAISE EXCEPTION 'BOOKING_CONFLICT'; END IF; v_id:=uuid_generate_v4(); INSERT INTO bookings(id,console_id,customer_id,booking_date,start_hour,start_minute,duration_minutes,status,notes,created_at,updated_at) VALUES(v_id,p_console_id,p_customer_id,p_booking_date,p_start_hour,p_start_minute,p_duration_minutes,'pending',p_notes,NOW(),NOW()); RETURN QUERY SELECT v_id,'pending'::VARCHAR; END; $$;

-- 20. byoneSellMembership
CREATE OR REPLACE FUNCTION "byoneSellMembership"(p_customer_id UUID, p_cash_received NUMERIC) RETURNS TABLE(customer_id UUID, membership_price NUMERIC, payment_id UUID, change_amount NUMERIC, message VARCHAR) LANGUAGE plpgsql AS $$ DECLARE v_customer customers%ROWTYPE; v_price NUMERIC(10,2); v_payment_id UUID; v_change NUMERIC(10,2); v_now TIMESTAMPTZ:=NOW(); BEGIN SELECT * INTO v_customer FROM customers WHERE customers.id=p_customer_id FOR UPDATE; IF NOT FOUND THEN RAISE EXCEPTION 'CUSTOMER_NOT_FOUND'; END IF; IF v_customer.is_member THEN RAISE EXCEPTION 'ALREADY_MEMBER'; END IF; SELECT COALESCE(value::NUMERIC,0) INTO v_price FROM app_settings WHERE key='membership_price'; IF v_price=0 THEN RAISE EXCEPTION 'PRICE_NOT_SET'; END IF; IF p_cash_received<v_price THEN RAISE EXCEPTION 'INSUFFICIENT_CASH'; END IF; v_change:=p_cash_received-v_price; UPDATE customers SET is_member=TRUE,membership_type='member',membership_start=CURRENT_DATE,membership_expiry=NULL,membership_price=v_price,updated_at=v_now WHERE customers.id=p_customer_id; v_payment_id:=uuid_generate_v4(); INSERT INTO payments(id,session_id,amount,total_payment,payment_method,payment_status,cash_received,change_amount,notes,paid_at,created_at,updated_at) VALUES(v_payment_id,NULL,v_price,v_price,'cash','paid',p_cash_received,v_change,'Membership lifetime',v_now,v_now,v_now); RETURN QUERY SELECT p_customer_id,v_price,v_payment_id,v_change,('Member aktif. Kembalian: Rp '||v_change::TEXT)::VARCHAR; END; $$;

-- 21. byoneDashboardSummary (daily rental + membership)
CREATE OR REPLACE FUNCTION "byoneDashboardSummary"(p_date DATE DEFAULT CURRENT_DATE) RETURNS TABLE(total_revenue NUMERIC, total_base_amount NUMERIC, total_transactions BIGINT, total_discount NUMERIC, total_auto_discount NUMERIC, voucher_usage_count BIGINT, total_cash_received NUMERIC, total_change NUMERIC, active_sessions INT, available_consoles INT, total_consoles INT, daily_rental_revenue NUMERIC, daily_rental_count BIGINT, membership_revenue NUMERIC, membership_count BIGINT, voucher_details JSONB) LANGUAGE plpgsql AS $$ BEGIN WITH payment_agg AS (SELECT COALESCE(SUM(p.total_payment),0) AS total_rev, COALESCE(SUM(p.amount),0) AS total_base, COUNT(*)::BIGINT AS total_trx, COALESCE(SUM(p.discount_amount),0) AS total_disc, COALESCE(SUM(p.auto_discount_amount),0) AS total_auto, COUNT(p.voucher_id)::BIGINT AS voucher_count, COALESCE(SUM(p.cash_received),0) AS total_cash, COALESCE(SUM(p.change_amount),0) AS total_chg FROM payments p WHERE p.payment_status='paid' AND p.session_id IS NOT NULL AND p.paid_at::DATE=p_date), daily_rental_agg AS (SELECT COALESCE(SUM(d.final_amount),0) AS rental_rev, COUNT(*)::BIGINT AS rental_count FROM daily_rentals d WHERE d.created_at::DATE=p_date), membership_agg AS (SELECT COALESCE(SUM(p.total_payment),0) AS member_rev, COUNT(*)::BIGINT AS member_count FROM payments p WHERE p.payment_status='paid' AND p.session_id IS NULL AND p.paid_at::DATE=p_date), voucher_agg AS (SELECT v.name AS voucher_name, v.code AS voucher_code, COUNT(*) AS usage_count, SUM(src.discount_amount) AS total_discount FROM (SELECT p.voucher_id, p.discount_amount FROM payments p WHERE p.payment_status='paid' AND p.voucher_id IS NOT NULL AND p.paid_at::DATE=p_date UNION ALL SELECT d.voucher_id, d.discount_amount FROM daily_rentals d WHERE d.voucher_id IS NOT NULL AND d.created_at::DATE=p_date) src JOIN vouchers v ON v.id=src.voucher_id GROUP BY v.id, v.name, v.code ORDER BY usage_count DESC) SELECT pa.total_rev+dra.rental_rev+ma.member_rev, pa.total_base, pa.total_trx+dra.rental_count+ma.member_count, pa.total_disc, pa.total_auto, pa.voucher_count+(SELECT COUNT(*)::BIGINT FROM daily_rentals WHERE voucher_id IS NOT NULL AND created_at::DATE=p_date), pa.total_cash, pa.total_chg, (SELECT COUNT(*)::INT FROM sessions WHERE status='active'), (SELECT COUNT(*)::INT FROM consoles WHERE status='available'), (SELECT COUNT(*)::INT FROM consoles), dra.rental_rev, dra.rental_count, ma.member_rev, ma.member_count, COALESCE((SELECT jsonb_agg(row_to_json(va)) FROM voucher_agg va),'[]'::JSONB) INTO total_revenue,total_base_amount,total_transactions,total_discount,total_auto_discount,voucher_usage_count,total_cash_received,total_change,active_sessions,available_consoles,total_consoles,daily_rental_revenue,daily_rental_count,membership_revenue,membership_count,voucher_details FROM payment_agg pa CROSS JOIN daily_rental_agg dra CROSS JOIN membership_agg ma; RETURN NEXT; END; $$;

-- 22. byoneReportSummary (rental + membership breakdown)
CREATE OR REPLACE FUNCTION "byoneReportSummary"(p_start_date DATE, p_end_date DATE) RETURNS TABLE(report JSONB) LANGUAGE plpgsql AS $$ DECLARE v_total_days INT; v_result JSONB; BEGIN IF p_start_date IS NULL THEN p_start_date:=CURRENT_DATE-7; END IF; IF p_end_date IS NULL THEN p_end_date:=CURRENT_DATE; END IF; IF p_start_date>p_end_date THEN RAISE EXCEPTION 'INVALID_DATE_RANGE'; END IF; v_total_days:=p_end_date-p_start_date+1; WITH session_rev AS (SELECT COALESCE(SUM(p.total_payment),0) AS revenue, COALESCE(SUM(p.amount),0) AS base_amount, COALESCE(SUM(p.discount_amount),0) AS discount, COALESCE(SUM(p.auto_discount_amount),0) AS auto_discount, COALESCE(SUM(p.cash_received),0) AS cash_received, COALESCE(SUM(p.change_amount),0) AS change_amount, COUNT(*)::INT AS trx_count, COUNT(p.voucher_id)::INT AS voucher_trx FROM payments p WHERE p.payment_status='paid' AND p.session_id IS NOT NULL AND p.paid_at::DATE BETWEEN p_start_date AND p_end_date), rental_rev AS (SELECT COALESCE(SUM(d.final_amount),0) AS revenue, COALESCE(SUM(d.total_amount),0) AS base_amount, COALESCE(SUM(d.discount_amount),0) AS discount, 0::NUMERIC AS auto_discount, COALESCE(SUM(d.final_amount),0) AS cash_received, 0::NUMERIC AS change_amount, COUNT(*)::INT AS trx_count, COUNT(d.voucher_id)::INT AS voucher_trx FROM daily_rentals d WHERE d.created_at::DATE BETWEEN p_start_date AND p_end_date), member_rev AS (SELECT COALESCE(SUM(p.total_payment),0) AS revenue, COALESCE(SUM(p.amount),0) AS base_amount, COALESCE(SUM(p.discount_amount),0) AS discount, 0::NUMERIC AS auto_discount, COALESCE(SUM(p.cash_received),0) AS cash_received, COALESCE(SUM(p.change_amount),0) AS change_amount, COUNT(*)::INT AS trx_count, 0::INT AS voucher_trx FROM payments p WHERE p.payment_status='paid' AND p.session_id IS NULL AND p.paid_at::DATE BETWEEN p_start_date AND p_end_date), combined AS (SELECT sr.revenue+rr.revenue+mr.revenue AS total_revenue, sr.base_amount+rr.base_amount+mr.base_amount AS total_base, sr.discount+rr.discount+mr.discount AS total_discount, sr.auto_discount+rr.auto_discount+mr.auto_discount AS total_auto, sr.cash_received+rr.cash_received+mr.cash_received AS total_cash, sr.change_amount+rr.change_amount+mr.change_amount AS total_change, sr.trx_count+rr.trx_count+mr.trx_count AS total_trx, sr.voucher_trx+rr.voucher_trx+mr.voucher_trx AS voucher_trx, rr.revenue AS rental_rev, rr.trx_count AS rental_count, mr.revenue AS member_rev, mr.trx_count AS member_count FROM session_rev sr CROSS JOIN rental_rev rr CROSS JOIN member_rev mr), session_agg AS (SELECT COUNT(*)::INT AS total_sessions, COALESCE(SUM(s.duration_minutes),0)::INT AS total_play_minutes, COALESCE(AVG(s.duration_minutes),0)::INT AS avg_duration_minutes FROM sessions s WHERE s.status='completed' AND s.created_at::DATE BETWEEN p_start_date AND p_end_date), voucher_usage AS (SELECT COALESCE(jsonb_agg(row_to_json(v) ORDER BY v."usageCount" DESC),'[]'::JSONB) AS list FROM (SELECT v.name AS "voucherName", v.code AS "voucherCode", v.discount_type AS "discountType", COUNT(*)::INT AS "usageCount", SUM(src.discount_amount)::NUMERIC(10,2) AS "totalDiscount" FROM (SELECT p.voucher_id, p.discount_amount FROM payments p WHERE p.payment_status='paid' AND p.voucher_id IS NOT NULL AND p.paid_at::DATE BETWEEN p_start_date AND p_end_date UNION ALL SELECT d.voucher_id, d.discount_amount FROM daily_rentals d WHERE d.voucher_id IS NOT NULL AND d.created_at::DATE BETWEEN p_start_date AND p_end_date) src JOIN vouchers v ON v.id=src.voucher_id GROUP BY v.id,v.name,v.code,v.discount_type) v), console_usage AS (SELECT COALESCE(jsonb_agg(row_to_json(c) ORDER BY c."totalMinutes" DESC),'[]'::JSONB) AS list FROM (SELECT c.name AS "consoleName", c.console_type AS "consoleType", COUNT(*)::INT AS "totalSessions", COALESCE(SUM(s.duration_minutes),0)::INT AS "totalMinutes" FROM sessions s JOIN consoles c ON c.id=s.console_id WHERE s.status='completed' AND s.created_at::DATE BETWEEN p_start_date AND p_end_date GROUP BY c.id,c.name,c.console_type) c), daily AS (SELECT COALESCE(jsonb_agg(row_to_json(d) ORDER BY d."date"),'[]'::JSONB) AS list FROM (SELECT dd::DATE AS "date", COALESCE(pd.rev,0)+COALESCE(drd.rev,0)+COALESCE(md.rev,0) AS "revenue", COALESCE(pd.trx,0)+COALESCE(drd.trx,0)+COALESCE(md.trx,0) AS "transactions", COALESCE(sd.sessions,0) AS "sessions", COALESCE(sd.playMinutes,0) AS "playMinutes", COALESCE(drd.rental_rev,0) AS "rentalRevenue", COALESCE(drd.rental_count,0) AS "dailyRentals", COALESCE(md.member_rev,0) AS "membershipRevenue", COALESCE(md.member_count,0) AS "memberships" FROM generate_series(p_start_date,p_end_date,'1 day'::INTERVAL) dd LEFT JOIN LATERAL (SELECT COALESCE(SUM(p.total_payment),0) AS rev, COUNT(*)::INT AS trx FROM payments p WHERE p.payment_status='paid' AND p.session_id IS NOT NULL AND p.paid_at::DATE=dd) pd ON TRUE LEFT JOIN LATERAL (SELECT COALESCE(SUM(d2.final_amount),0) AS rev, COALESCE(SUM(d2.total_amount),0) AS rental_rev, COUNT(*)::INT AS trx, COUNT(*)::INT AS rental_count FROM daily_rentals d2 WHERE d2.created_at::DATE=dd) drd ON TRUE LEFT JOIN LATERAL (SELECT COALESCE(SUM(p2.total_payment),0) AS rev, COALESCE(SUM(p2.amount),0) AS member_rev, COUNT(*)::INT AS trx, COUNT(*)::INT AS member_count FROM payments p2 WHERE p2.payment_status='paid' AND p2.session_id IS NULL AND p2.paid_at::DATE=dd) md ON TRUE LEFT JOIN LATERAL (SELECT COUNT(*)::INT AS sessions, COALESCE(SUM(s2.duration_minutes),0)::INT AS playMinutes FROM sessions s2 WHERE s2.status='completed' AND s2.created_at::DATE=dd) sd ON TRUE) d), discount_rules_summary AS (SELECT COALESCE(jsonb_agg(row_to_json(dr)),'[]'::JSONB) AS list FROM (SELECT dr.name AS "ruleName", dr.rule_type AS "ruleType", dr.discount_type AS "discountType", dr.discount_value AS "discountValue", dr.is_active AS "isActive" FROM discount_rules dr WHERE dr.is_active=TRUE ORDER BY dr.rule_type,dr.name) dr) SELECT jsonb_build_object('period',jsonb_build_object('startDate',p_start_date,'endDate',p_end_date,'totalDays',v_total_days),'revenue',jsonb_build_object('totalRevenue',cb.total_revenue,'totalBaseAmount',cb.total_base,'voucherDiscount',cb.total_discount,'autoDiscount',cb.total_auto,'totalDiscount',cb.total_discount+cb.total_auto,'totalCashReceived',cb.total_cash,'totalChange',cb.total_change,'dailyRentalRevenue',cb.rental_rev,'dailyRentalCount',cb.rental_count,'membershipRevenue',cb.member_rev,'membershipCount',cb.member_count),'transactions',jsonb_build_object('totalTransactions',cb.total_trx,'voucherTransactions',cb.voucher_trx,'averagePerDay',ROUND(cb.total_trx::NUMERIC/GREATEST(v_total_days,1),1)),'sessions',jsonb_build_object('totalSessions',sa.total_sessions,'totalPlayMinutes',sa.total_play_minutes,'totalPlayHours',ROUND(sa.total_play_minutes::NUMERIC/60.0,1),'averageMinutes',sa.avg_duration_minutes),'vouchers',vu.list,'consoles',cu.list,'dailyBreakdown',d.list,'activeDiscountRules',dr.list,'generatedAt',NOW()) INTO v_result FROM combined cb CROSS JOIN session_agg sa CROSS JOIN voucher_usage vu CROSS JOIN console_usage cu CROSS JOIN daily d CROSS JOIN discount_rules_summary dr; RETURN QUERY SELECT v_result; END; $$;

-- 23. byoneLogTvActivity (sleep/screensaver support)
CREATE OR REPLACE FUNCTION "byoneLogTvActivity"(p_console_id UUID, p_event VARCHAR, p_session_id UUID DEFAULT NULL) RETURNS TABLE(log_id UUID, is_authorized BOOLEAN, session_id UUID, duration_minutes INT, message VARCHAR) LANGUAGE plpgsql AS $$ DECLARE v_log_id UUID; v_session_id UUID:=NULL; v_authorized BOOLEAN:=FALSE; v_duration INT:=NULL; v_last_on TIMESTAMPTZ; v_msg VARCHAR:=''; v_now TIMESTAMPTZ:=NOW(); BEGIN IF NOT EXISTS(SELECT 1 FROM consoles WHERE id=p_console_id) THEN RAISE EXCEPTION 'CONSOLE_NOT_FOUND'; END IF; IF p_event='on' THEN SELECT s.id INTO v_session_id FROM sessions s WHERE s.console_id=p_console_id AND s.status='active' ORDER BY s.start_time DESC LIMIT 1; v_authorized:=(v_session_id IS NOT NULL); v_msg:=CASE WHEN v_authorized THEN 'TV menyala - SESI AKTIF' ELSE 'TV menyala - TANPA SESI (unauthorized)' END; v_log_id:=uuid_generate_v4(); INSERT INTO tv_activity_logs(id,console_id,event,session_id,is_authorized,created_at) VALUES(v_log_id,p_console_id,'on',v_session_id,v_authorized,v_now); ELSE SELECT created_at INTO v_last_on FROM tv_activity_logs WHERE console_id=p_console_id AND event='on' ORDER BY created_at DESC LIMIT 1; SELECT s.id INTO v_session_id FROM sessions s WHERE s.console_id=p_console_id AND s.status='active' ORDER BY s.start_time DESC LIMIT 1; v_authorized:=(v_session_id IS NOT NULL); IF v_last_on IS NOT NULL THEN v_duration:=EXTRACT(EPOCH FROM (v_now-v_last_on))/60; END IF; v_log_id:=uuid_generate_v4(); INSERT INTO tv_activity_logs(id,console_id,event,session_id,is_authorized,duration_minutes,created_at) VALUES(v_log_id,p_console_id,p_event,v_session_id,v_authorized,v_duration,v_now); v_msg:='TV '||p_event||'. '; IF v_duration IS NOT NULL THEN v_msg:=v_msg||'Durasi: '||v_duration||' menit. '; END IF; v_msg:=v_msg||CASE WHEN v_authorized THEN 'Sesi aktif.' ELSE 'Tanpa sesi.' END; END IF; RETURN QUERY SELECT v_log_id,v_authorized,v_session_id,v_duration,v_msg; END; $$;

-- 24. byoneGetTvLogs (unauthorized_logs list)
CREATE OR REPLACE FUNCTION "byoneGetTvLogs"(p_console_id UUID, p_date DATE DEFAULT NULL) RETURNS TABLE(logs JSONB, unauthorized_count BIGINT, total_on_minutes BIGINT, active_session JSONB, unauthorized_logs JSONB) LANGUAGE plpgsql AS $$ DECLARE v_logs_json JSONB; v_unauth BIGINT; v_total_min BIGINT; v_session_json JSONB; v_unauth_logs JSONB; BEGIN SELECT COALESCE(jsonb_agg(row_to_json(l) ORDER BY l.sort_order DESC),'[]'::JSONB) INTO v_logs_json FROM (SELECT t.id, t.event, t.is_authorized AS "isAuthorized", t.duration_minutes AS "durationMinutes", t.session_id AS "sessionId", to_char(t.created_at,'YYYY-MM-DD"T"HH24:MI:SS"Z"') AS "createdAt", c.name AS "consoleName", t.created_at AS sort_order FROM tv_activity_logs t JOIN consoles c ON c.id=t.console_id WHERE t.console_id=p_console_id AND (p_date IS NULL OR t.created_at::DATE=p_date) ORDER BY t.created_at DESC LIMIT 100) l; SELECT COALESCE(jsonb_agg(row_to_json(u) ORDER BY u.sort_order DESC),'[]'::JSONB) INTO v_unauth_logs FROM (SELECT t.id, t.event, t.is_authorized AS "isAuthorized", t.duration_minutes AS "durationMinutes", to_char(t.created_at,'YYYY-MM-DD"T"HH24:MI:SS"Z"') AS "createdAt", t.created_at AS sort_order FROM tv_activity_logs t WHERE t.console_id=p_console_id AND t.is_authorized=FALSE AND (p_date IS NULL OR t.created_at::DATE=p_date) ORDER BY t.created_at DESC LIMIT 20) u; SELECT COUNT(*) INTO v_unauth FROM tv_activity_logs WHERE console_id=p_console_id AND event='on' AND is_authorized=FALSE AND (p_date IS NULL OR created_at::DATE=p_date); SELECT COALESCE(SUM(duration_minutes),0) INTO v_total_min FROM tv_activity_logs WHERE console_id=p_console_id AND event IN('off','sleep','screensaver') AND duration_minutes IS NOT NULL AND (p_date IS NULL OR created_at::DATE=p_date); SELECT COALESCE(to_jsonb(s),'null'::JSONB) INTO v_session_json FROM (SELECT s.id AS "sessionId", s.start_time AS "startTime", s.booked_duration_minutes AS "bookedMinutes", EXTRACT(EPOCH FROM (NOW()-s.start_time))/60 AS "runningMinutes", s.status, cust.name AS "customerName" FROM sessions s LEFT JOIN customers cust ON cust.id=s.customer_id WHERE s.console_id=p_console_id AND s.status='active' ORDER BY s.start_time DESC LIMIT 1) s; RETURN QUERY SELECT v_logs_json,v_unauth,v_total_min,v_session_json,v_unauth_logs; END; $$;
